#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include <limits.h>
#include <stdbool.h>
#include <string.h>

#ifndef DEFAULT_ORDER_2
#define DEFAULT_ORDER_2 256
#endif

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER_2 + 1];
	int  keys [DEFAULT_ORDER_2 + 1];
	bool is_leaf;
	int num_keys;
} knode;

void 
kernel_cpu_2(	int cores_arg,
				knode *knodes,
				long knodes_elem,

				int order,
				long maxheight,
				int count,

				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	// Parallelize over the number of queries (blocks)
	#pragma omp parallel for num_threads(cores_arg > 0 ? cores_arg : omp_get_max_threads())
	int bid = 0;
	for(bid = 0; bid < count; bid++){
		long current_knode = currKnode[bid];
		long offset_val = offset[bid];
		int start_val = start[bid];

		long last_knode = lastKnode[bid];
		long offset_2_val = offset_2[bid];
		int end_val = end[bid];

		int i;
		for(i = 0; i < maxheight; i++){
			// Process start path
			int thid = 0;
			for(thid = 0; thid < order; thid++){
				if((knodes[current_knode].keys[thid] <= start_val) && (knodes[current_knode].keys[thid+1] > start_val)){
					if(knodes[current_knode].indices[thid] < knodes_elem){
						offset_val = knodes[current_knode].indices[thid];
					}
					break;
				}
			}

			// Process end path
			for(thid = 0; thid < order; thid++){
				if((knodes[last_knode].keys[thid] <= end_val) && (knodes[last_knode].keys[thid+1] > end_val)){
					if(knodes[last_knode].indices[thid] < knodes_elem){
						offset_2_val = knodes[last_knode].indices[thid];
					}
					break;
				}
			}

			// Update for next level
			current_knode = offset_val;
			last_knode = offset_2_val;
		}

		// Finalize start
		int thid = 0;
		for(thid = 0; thid < order; thid++){
			if(knodes[current_knode].keys[thid] == start_val){
				recstart[bid] = knodes[current_knode].indices[thid];
				break;
			}
		}

		// Finalize length
		for(thid = 0; thid < order; thid++){
			if(knodes[last_knode].keys[thid] == end_val){
				reclength[bid] = knodes[last_knode].indices[thid] - recstart[bid] + 1;
				break;
			}
		}
	}
}

void 
kernel_gpu_opencl_wrapper_2(knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							long *lastKnode,
							long *offset_2,
							int *start,
							int *end,
							int *recstart,
							int *reclength)
{
	int cores = omp_get_max_threads();
	if(cores == 0) cores = 1;
	kernel_cpu_2(cores, knodes, knodes_elem, order, maxheight, count, currKnode, offset, lastKnode, offset_2, start, end, recstart, reclength);
}
